int needed(vector<long long> v, long long limit) {
    sort(v.rbegin(), v.rend());
    long long sum = 0;
    for (int i = 0; i < (int)v.size(); ++i) {
        sum += v[i];
        if (sum > limit) return i + 1;
    }
    return (int)v.size();
}

