int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n;
    long long m;
    cin >> n >> m;
    vector<long long> a(n);
    long long total = 0, mx = 0;
    for (auto &x : a) { cin >> x; total += x; mx = max(mx, x); }
    if (total <= m) {
        cout << "infinite\n";
        return 0;
    }
    long long low = 0, high = mx;
    auto ok = [&](long long cap) {
        long long sum = 0;
        for (long long x : a) sum += min(x, cap);
        return sum <= m;
    };
    while (high - low > 1) {
        long long mid = (low + high) / 2;
        if (ok(mid)) low = mid;
        else high = mid;
    }
    cout << low << '\n';
    return 0;
}

