int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, mg;
    cin >> n >> mg;
    vector<vector<int>> g(n, vector<int>(n, 0)), h(n, vector<int>(n, 0));
    for (int i = 0; i < mg; ++i) {
        int u, v;
        cin >> u >> v;
        --u; --v;
        g[u][v] = g[v][u] = 1;
    }
    int mh;
    cin >> mh;
    for (int i = 0; i < mh; ++i) {
        int a, b;
        cin >> a >> b;
        --a; --b;
        h[a][b] = h[b][a] = 1;
    }
    vector<vector<long long>> cost(n, vector<long long>(n, 0));
    for (int i = 0; i < n - 1; ++i) {
        for (int j = i + 1; j < n; ++j) cin >> cost[i][j];
    }
    vector<int> p(n);
    iota(p.begin(), p.end(), 0);
    long long ans = numeric_limits<long long>::max();
    do {
        long long cur = 0;
        for (int i = 0; i < n; ++i) for (int j = i + 1; j < n; ++j) {
            int x = p[i], y = p[j];
            if (x > y) swap(x, y);
            if (g[i][j] != h[p[i]][p[j]]) cur += cost[x][y];
        }
        ans = min(ans, cur);
    } while (next_permutation(p.begin(), p.end()));
    cout << ans << '\n';
    return 0;
}

