// 参考解：按题意实现核心算法。
int distance_without_block(int n, int from, int to, int block) {
    int cw = (to - from + n) % n;
    bool ok_cw = true;
    for (int step = 1; step <= cw; ++step) if ((from + step) % n == block) ok_cw = false;
    int ccw = (from - to + n) % n;
    bool ok_ccw = true;
    for (int step = 1; step <= ccw; ++step) if ((from - step + n) % n == block) ok_ccw = false;
    int res = 1e9;
    if (ok_cw) res = min(res, cw);
    if (ok_ccw) res = min(res, ccw);
    return res;
}

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, q;
    cin >> n >> q;
    int left = 0, right = 1;
    long long ans = 0;
    while (q--) {
        char hand;
        int t;
        cin >> hand >> t;
        --t;
        if (hand == 'L') {
            ans += distance_without_block(n, left, t, right);
            left = t;
        } else {
            ans += distance_without_block(n, right, t, left);
            right = t;
        }
    }
    cout << ans << '\n';
    return 0;
}

