int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);

    int n, k;
    string s;
    cin >> n >> k >> s;
    vector<pair<char,int>> seg;
    for (char ch : s) {
        if (seg.empty() || seg.back().first != ch) seg.push_back({ch, 1});
        else ++seg.back().second;
    }
    vector<int> one_indices;
    for (int i = 0; i < (int)seg.size(); ++i) if (seg[i].first == '1') one_indices.push_back(i);
    int idx = one_indices[k - 1];
    swap(seg[idx - 1], seg[idx]);
    string ans;
    for (auto [ch, len] : seg) ans.append(len, ch);
    cout << ans << '\n';
    return 0;
}
